import{_ as a,c as e,a1 as n,o as t}from"./chunks/framework.BDxlaA_J.js";const h=JSON.parse('{"title":"Avoiding Scanning Detection using Multiple Decoy IP Addresses","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/2-scanning-networks/5-NmapDecoyIP.md","filePath":"categories/ethical-hacking-labs/2-scanning-networks/5-NmapDecoyIP.md"}'),p={name:"categories/ethical-hacking-labs/2-scanning-networks/5-NmapDecoyIP.md"};function i(o,s,r,c,d,l){return t(),e("div",null,s[0]||(s[0]=[n(`<h1 id="avoiding-scanning-detection-using-multiple-decoy-ip-addresses" tabindex="-1">Avoiding Scanning Detection using Multiple Decoy IP Addresses <a class="header-anchor" href="#avoiding-scanning-detection-using-multiple-decoy-ip-addresses" aria-label="Permalink to &quot;Avoiding Scanning Detection using Multiple Decoy IP Addresses&quot;">​</a></h1><p>The Nmap command <code>nmap -D RND:10</code> is the decoy option, that lets you scan using multiple decoy IP addresses.</p><p>Firewalls and IDS detect normal scanning attempts on the target network. However, you can use the IP address decoy technique to avoid detection.</p><p><strong>Before starting this lab, make sure that you have your Windows Firewall on the target turned on.</strong></p><h2 id="ip-fragmentation" tabindex="-1">IP Fragmentation <a class="header-anchor" href="#ip-fragmentation" aria-label="Permalink to &quot;IP Fragmentation&quot;">​</a></h2><p>Open a new Terminal window on Kali and enter the target IP address (Windows).</p><p><code>nmap -f &lt;Target IP Address&gt;</code></p><p><code>-f</code>: Used to scan tiny fragment packets.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.00074s latency).</span></span>
<span class="line"><span>Not shown: 979 filtered ports</span></span>
<span class="line"><span>PORT      STATE SERVICE</span></span>
<span class="line"><span>53/tcp    open  domain</span></span>
<span class="line"><span>80/tcp    open  http</span></span>
<span class="line"><span>88/tcp    open  kerberos-sec</span></span>
<span class="line"><span>135/tcp   open  msrpc</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn</span></span>
<span class="line"><span>389/tcp   open  ldap</span></span>
<span class="line"><span>443/tcp   open  https</span></span>
<span class="line"><span>445/tcp   open  microsoft-ds</span></span>
<span class="line"><span>464/tcp   open  kpasswd5</span></span>
<span class="line"><span>593/tcp   open  http-rpc-epmap</span></span>
<span class="line"><span>636/tcp   open  ldapssl</span></span>
<span class="line"><span>3268/tcp  open  globalcatLDAP</span></span>
<span class="line"><span>3269/tcp  open  globalcatLDAPssl</span></span>
<span class="line"><span>3389/tcp  open  ms-wbt-server</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Nmap done: 1 IP address (1 host up) scanned in 13.72 seconds</span></span></code></pre></div><p>When the Windows Firewall service is turned on, you can only see the ports opened as shown in the output above.</p><h2 id="perform-maximum-transmission-unit" tabindex="-1">Perform Maximum Transmission Unit <a class="header-anchor" href="#perform-maximum-transmission-unit" aria-label="Permalink to &quot;Perform Maximum Transmission Unit&quot;">​</a></h2><p>This command is used to transmit smaller packets instead of sending one complete packet at a time.</p><p>This scan is very similar to the previous one but with <strong>Maximum Transmission Unit</strong> (<code>-mtu</code>) and <code>8</code> bytes of packets.</p><p><code>nmap -mtu 8 &lt;Target IP Address&gt;</code></p><p>If everything works, the results should be identical to the previous one.</p><h2 id="decoying-ip-address" tabindex="-1">Decoying IP address <a class="header-anchor" href="#decoying-ip-address" aria-label="Permalink to &quot;Decoying IP address&quot;">​</a></h2><p>This command is used to scan multiple decoy IP addresses. Nmap will send multiple packets with different IP addresses, along with your attacker&#39;s IP address.</p><p><code>nmap -D RND:10 &lt;Target IP Address&gt;</code></p><p>Again, the output is the same as previous outputs but on the target view is very different.</p><p>Check the Logs on your Windows Server Firewall and analyze the last scan performed. You also can analyze this information with Wireshark turned on.</p><p>Both shows multiple IP addresses along with your real attacker IP address.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6c4f716f549aedea473d2701b1f40bb592413e47/firewallLog-RND.png" alt="firewall"><em>Windows Firewall Log: Decoyed IP Address</em></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6c4f716f549aedea473d2701b1f40bb592413e47/wireshark-RND.png" alt="wireshark"><em>Wireshark: Decoyed IP Address</em></p>`,23)]))}const u=a(p,[["render",i]]);export{h as __pageData,u as default};
